    task:
      id: 79dd7969-c8c9-43be-8c2e-f96541b23696
      version: -1
      name: Is breached data encrypted?
      description: Check if breached data has been encrypted. If breached data is
        encrypted and the encryption has not been compromised, there is no need for
        breach notification.
      type: condition
      iscommand: false
      brand: ""
    nexttasks:
      '#default#':
      - "54"
      "yes":
      - "2"
    separatecontext: false
    conditions:
    - label: "yes"
      condition:
      - - operator: isEqualString
          left:
            value:
              complex:
                root: incident
                accessor: dataencryptionstatus
            iscontext: true
          right:
            value:
              simple: Full
          ignorecase: true
    view: |-
      {
        "position": {
          "x": 600,
          "y": -530
        }
      }
    note: false
    timertriggers: []
    ignoreworker: false
  "2":
