      name: Has encryption been compromised?
      description: |
        Are the encryption keys or the encrypted data compromised in any way?
      type: condition
      iscommand: false
      brand: ""
    nexttasks:
      "No":
      - "3"
      "Yes":
      - "54"
    separatecontext: false
    view: |-
      {
        "position": {
