    type: collection
    task:
      id: d4ee7b93-d2a3-4373-829d-617a5e2db8e7
      version: -1
      name: Analyst review
      description: Checks with the analyst if the key was compromised.
      type: collection
      iscommand: false
      brand: ""
    nexttasks:
      '#none#':
      - "4"
    separatecontext: false
    view: |-
      {
        "position": {
          "x": 1070,
          "y": -190
        }
      }
    note: false
    timertriggers: []
    ignoreworker: false
    message:
      to:
        simple: Analyst
      subject:
        simple: ${incident.rawName} | Analyst review required
      body:
        simple: |-
          Hello,

          A HIPAA breach incident has been opened.
          The breached data is encrypted, and the encryption key was not compromised.

          Please review the information and the incident details to make sure there was no breach.
