      - email
      format: ""
      bcc:
      cc:
      timings:
        retriescount: 2
        retriesinterval: 360
        completeafterreplies: 1
    form:
      questions:
      - id: "0"
        label: ""
        labelarg:
          simple: Is the Private Health Information (PHI) data secure?
        required: false
        gridcolumns: []
        defaultrows: []
        type: singleSelect
        options:
        - "Yes"
        - "No"
        fieldassociated: ""
        placeholder: ""
        tooltip: ""
        readonly: false
      title: Analyst review
      description: |-
        A HIPAA breach incident has been opened.
        The breached data is encrypted, and the encryption key was not compromised.

        Please review the information and the incident details to make sure there was no breach.
      sender: ""
      expired: false
      totalanswers: 0
