      name: Notify DPO of suspected PHI data breach
      description: |
        Notifies the Data Protection Officer of a suspected PHI data breach.
      type: collection
      iscommand: false
      brand: ""
    nexttasks:
      '#none#':
      - "7"
    separatecontext: false
    view: |-
      {
        "position": {
          "x": 600,
          "y": 340
        }
      }
    note: false
    timertriggers: []
    ignoreworker: false
    message:
      to:
        complex:
          root: incident
          accessor: dpoemailaddress
      subject:
        simple: Suspected PHI Data Breach in your organization
      body:
        simple: |-
          Hello,
          A suspected data breach has occurred in your organization and requires your attention.
          Data breach details:
          Company: ${inputs.CompanyName}
          State: ${incident.statewherethebreachtookplace}
          Date/Time: ${incident.datetimeofthebreach}
          Affected data type: ${incident.affecteddata}
          Approx. # of affected data subjects: ${incident.approximatenumberofaffecteddatasubjects}
          Data encryption status: ${incident.dataencryptionstatus}
          Where data is hosted: ${incident.whereisdatahosted}
          The suspected cause of the breach: ${incident.possiblecauseofthebreach}
          If the cause is malicious, what the specific cause might have been: ${incident.maliciouscauseifthecauseisamaliciousattack}
          Refer to the 'California legislative information' site for more details about the notification process: https://www.hhs.gov/hipaa/for-professionals/breach-notification/index.html
          Please complete the following form to continue the data breach investigation.
      methods:
      - email
      format: ""
      bcc:
      cc:
      timings:
        retriescount: 2
        retriesinterval: 360
        completeafterreplies: 1
    form:
      questions:
      - id: "0"
        label: ""
        labelarg:
          simple: In your assessment, does the breach involve Private Health Information
            (PHI) of living individuals?
        required: true
        gridcolumns: []
        defaultrows: []
        type: singleSelect
        options:
        - "Yes"
        - "No"
        fieldassociated: ""
        placeholder: ""
        tooltip: If the answer is 'Yes', the breach will be documented. Please fill
          out the following questions.
        readonly: false
      - id: "1"
        label: ""
        labelarg:
          simple: How likely is it that the breach will result in a risk to individuals?
        required: false
        gridcolumns: []
        defaultrows: []
        type: singleSelect
        options:
        - Likely
        - Unlikely
        fieldassociated: ""
        placeholder: ""
        tooltip: Risk - The resulting risk of the impact of the breach on individuals.
          When assessing the risk to individuals as a result of a breach, the DPO
          should consider the specific circumstances of the breach, including the
          severity of the potential impact and the likelihood of this occurring. If
          the answer is 'Likely' to result in a risk to individuals, please fill out
          the next question, and the section regarding the information for the breach
          report.
        readonly: false
      - id: "2"
        label: ""
        labelarg:
          simple: Are you aware of the cause of the breach?
        required: false
        gridcolumns: []
        defaultrows: []
        type: multiSelect
        options:
        - ""
        - Malicious attack - internal
        - Malicious attack - external
        - Accident (system failure)
        - Negligence (human error)
        - Other
        fieldassociated: ""
        placeholder: ""
        tooltip: ""
        readonly: false
      - id: "3"
        label: ""
        labelarg:
          simple: If a result of a malicious attack, what caused the breach?
        required: false
        gridcolumns: []
        defaultrows: []
        type: multiSelect
        options:
        - Unknown vulnerability
        - Cryptolockers
        - Reconnaissance
        - Phishing
        - Distributed denial of service
        - Malware
        - Social engineering
        - Other
        fieldassociated: ""
        placeholder: ""
        tooltip: ""
        readonly: false
      - id: "4"
        label: ""
        labelarg:
          simple: What is the likely impact of the breach?
        required: false
        gridcolumns: []
        defaultrows: []
        type: multiSelect
        options:
        - ""
        - Data publication
        - Data theft
        - Identity theft or fraud
        - Loss of data
        - Loss of confidentiality of personal data
        - Business interruption
        - Liability issues
        - Damage to the reputation
        - Other
        fieldassociated: ""
        placeholder: ""
        tooltip: ""
        readonly: false
      - id: "5"
        label: ""
        labelarg:
          simple: |-
            What measures have been taken to mitigate the adverse effects of the
            breach?
        required: false
        gridcolumns: []
        defaultrows: []
        type: longText
        options: []
        fieldassociated: ""
        placeholder: ""
        tooltip: ""
        readonly: false
      - id: "6"
        label: ""
        labelarg:
          simple: Additional information that is relevant to the case
        required: false
        gridcolumns: []
        defaultrows: []
        type: longText
        options: []
        fieldassociated: ""
        placeholder: ""
        tooltip: ""
        readonly: false
      - id: "7"
        label: ""
        labelarg:
          simple: What should the residents do?
        required: false
        gridcolumns: []
        defaultrows: []
        type: longText
        options: []
        fieldassociated: ""
        placeholder: ""
        tooltip: ""
        readonly: false
      title: Suspected PHI data breach
      description: A suspected PHI data breach was found in your organization
      sender: ""
      expired: false
      totalanswers: 0
